import { BotEvent, MedplumClient } from '@medplum/core';
import { Bundle, Patient } from '@medplum/fhirtypes';

export async function handler(medplum: MedplumClient, event: BotEvent): Promise<any> {
  const hl7 = event.input as string;
  const mrn = hl7.split('\r')[1].split('|')[3].split('^')[0];
  const patient: Patient = {
    resourceType: 'Patient',
    identifier: [{ system: 'https://example.org/mrn', value: mrn }]
  };
  return medplum.createResourceIfNoneExist(patient, `identifier=${mrn}`);
}
